<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>WastedToken Mint — Collectible Challenge Coins</title>
<style>
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
:root{--gold:#d4a843;--gold-light:#f0d078;--gold-dark:#8a6a20;--bg:#08080e;--bg2:#0e0e18;--text:#e8e0d0;--text-dim:#8a8070}
html{scroll-behavior:smooth}
body{background:var(--bg);color:var(--text);font-family:Georgia,'Times New Roman',serif;line-height:1.6;overflow-x:hidden}
h1,h2,h3{font-weight:400;letter-spacing:.04em}
a{color:var(--gold);text-decoration:none}

/* Header */
header{text-align:center;padding:2.5rem 1rem 1rem;border-bottom:1px solid rgba(212,168,67,.15)}
header h1{font-size:clamp(1.6rem,4vw,2.8rem);color:var(--gold);text-transform:uppercase;letter-spacing:.15em}
header p{color:var(--text-dim);font-size:.95rem;margin-top:.4rem;font-style:italic}

/* Hero */
#hero{display:flex;justify-content:center;align-items:center;padding:2rem 1rem;position:relative}
#coin-hero{border-radius:12px;box-shadow:0 0 60px rgba(212,168,67,.12),0 0 120px rgba(212,168,67,.04)}

/* About */
#about{max-width:820px;margin:0 auto;padding:3rem 2rem;text-align:center}
#about h2{font-size:1.8rem;color:var(--gold);margin-bottom:1.2rem;letter-spacing:.1em}
#about p{color:var(--text-dim);font-size:1.05rem;margin-bottom:1rem}
#about .divider{width:80px;height:1px;background:linear-gradient(90deg,transparent,var(--gold),transparent);margin:1.5rem auto}

/* Collection */
#collection{max-width:1100px;margin:0 auto;padding:3rem 2rem 4rem}
#collection h2{text-align:center;font-size:1.8rem;color:var(--gold);margin-bottom:2rem;letter-spacing:.1em}
.edition-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(240px,1fr));gap:2rem;justify-items:center}
.edition{background:var(--bg2);border:1px solid rgba(212,168,67,.12);border-radius:12px;padding:1.2rem;text-align:center;transition:transform .3s,box-shadow .3s;position:relative;overflow:hidden}
.edition:hover{transform:translateY(-4px);box-shadow:0 8px 30px rgba(212,168,67,.1)}
.edition canvas{display:block;margin:0 auto 1rem;border-radius:8px}
.edition h3{font-size:1.1rem;color:var(--gold-light);margin-bottom:.3rem;letter-spacing:.06em}
.edition .status{font-size:.8rem;color:var(--text-dim);margin-bottom:.8rem;text-transform:uppercase;letter-spacing:.08em}
.edition .status.sold-out{color:#c0392b}
.edition .status.coming-soon{color:#3498db}
button.buy{background:linear-gradient(135deg,var(--gold),var(--gold-dark));color:#1a1a2e;border:none;padding:.6rem 1.6rem;border-radius:6px;font-family:inherit;font-size:.9rem;cursor:pointer;letter-spacing:.04em;transition:opacity .2s,transform .2s}
button.buy:hover{opacity:.85;transform:scale(1.03)}
button.buy:disabled{opacity:.3;cursor:not-allowed;transform:none}

/* Footer */
footer{text-align:center;padding:2rem;border-top:1px solid rgba(212,168,67,.1);color:var(--text-dim);font-size:.8rem}

/* Scrollbar */
::-webkit-scrollbar{width:8px}
::-webkit-scrollbar-track{background:var(--bg)}
::-webkit-scrollbar-thumb{background:var(--gold-dark);border-radius:4px}
</style>
</head>
<body>

<header>
  <h1>WastedToken Mint</h1>
  <p>Forged in fire. Backed by nothing. Collect them all.</p>
</header>

<section id="hero">
  <canvas id="coin-hero" width="800" height="600"></canvas>
