<script>
(function(){
"use strict";

/* ===== MATRIX UTILITIES ===== */
const M4={
  create(){return new Float32Array(16)},
  identity(o){o=o||M4.create();o.fill(0);o[0]=o[5]=o[10]=o[15]=1;return o},
  perspective(o,fov,asp,n,f){const t=1/Math.tan(fov/2),r=1/(n-f);o[0]=t/asp;o[1]=0;o[2]=0;o[3]=0;o[4]=0;o[5]=t;o[6]=0;o[7]=0;o[8]=0;o[9]=0;o[10]=(f+n)*r;o[11]=-1;o[12]=0;o[13]=2*f*n*r;o[14]=0;o[15]=0;return o},
  multiply(o,a,b){
    const a00=a[0],a01=a[1],a02=a[2],a03=a[3],a10=a[4],a11=a[5],a12=a[6],a13=a[7],
          a20=a[8],a21=a[9],a22=a[10],a23=a[11],a30=a[12],a31=a[13],a32=a[14],a33=a[15];
    let b0,b1,b2,b3;
    b0=b[0];b1=b[1];b2=b[2];b3=b[3];
    o[0]=b0*a00+b1*a10+b2*a20+b3*a30;o[1]=b0*a01+b1*a11+b2*a21+b3*a31;
    o[2]=b0*a02+b1*a12+b2*a22+b3*a32;o[3]=b0*a03+b1*a13+b2*a23+b3*a33;
    b0=b[4];b1=b[5];b2=b[6];b3=b[7];
    o[4]=b0*a00+b1*a10+b2*a20+b3*a30;o[5]=b0*a01+b1*a11+b2*a21+b3*a31;
    o[6]=b0*a02+b1*a12+b2*a22+b3*a32;o[7]=b0*a03+b1*a13+b2*a23+b3*a33;
    b0=b[8];b1=b[9];b2=b[10];b3=b[11];
    o[8]=b0*a00+b1*a10+b2*a20+b3*a30;o[9]=b0*a01+b1*a11+b2*a21+b3*a31;
    o[10]=b0*a02+b1*a12+b2*a22+b3*a32;o[11]=b0*a03+b1*a13+b2*a23+b3*a33;
    b0=b[12];b1=b[13];b2=b[14];b3=b[15];
    o[12]=b0*a00+b1*a10+b2*a20+b3*a30;o[13]=b0*a01+b1*a11+b2*a21+b3*a31;
    o[14]=b0*a02+b1*a12+b2*a22+b3*a32;o[15]=b0*a03+b1*a13+b2*a23+b3*a33;
    return o;
  },
  translate(o,a,v){
    const x=v[0],y=v[1],z=v[2];
    if(a===o){o[12]+=a[0]*x+a[4]*y+a[8]*z;o[13]+=a[1]*x+a[5]*y+a[9]*z;o[14]+=a[2]*x+a[6]*y+a[10]*z;o[15]+=a[3]*x+a[7]*y+a[11]*z;}
    else{
      const a00=a[0],a01=a[1],a02=a[2],a03=a[3],a10=a[4],a11=a[5],a12=a[6],a13=a[7],
            a20=a[8],a21=a[9],a22=a[10],a23=a[11],a30=a[12],a31=a[13],a32=a[14],a33=a[15];
      o[0]=a00;o[1]=a01;o[2]=a02;o[3]=a03;o[4]=a10;o[5]=a11;o[6]=a12;o[7]=a13;
      o[8]=a20;o[9]=a21;o[10]=a22;o[11]=a23;
      o[12]=a00*x+a10*y+a20*z+a30;o[13]=a01*x+a11*y+a21*z+a31;
      o[14]=a02*x+a12*y+a22*z+a32;o[15]=a03*x+a13*y+a23*z+a33;
    }return o;
  },
  rotateX(o,a,r){
    const s=Math.sin(r),c=Math.cos(r),a10=a[4],a11=a[5],a12=a[6],a13=a[7],a20=a[8],a21=a[9],a22=a[10],a23=a[11];
    if(a!==o){o[0]=a[0];o[1]=a[1];o[2]=a[2];o[3]=a[3];o[12]=a[12];o[13]=a[13];o[14]=a[14];o[15]=a[15];}
    o[4]=a10*c+a20*s;o[5]=a11*c+a21*s;o[6]=a12*c+a22*s;o[7]=a13*c+a23*s;
    o[8]=a20*c-a10*s;o[9]=a21*c-a11*s;o[10]=a22*c-a12*s;o[11]=a23*c-a13*s;
    return o;
  },
  rotateY(o,a,r){
    const s=Math.sin(r),c=Math.cos(r),a00=a[0],a01=a[1],a02=a[2],a03=a[3],a20=a[8],a21=a[9],a22=a[10],a23=a[11];
    if(a!==o){o[4]=a[4];o[5]=a[5];o[6]=a[6];o[7]=a[7];o[12]=a[12];o[13]=a[13];o[14]=a[14];o[15]=a[15];}
    o[0]=a00*c-a20*s;o[1]=a01*c-a21*s;o[2]=a02*c-a22*s;o[3]=a03*c-a23*s;
    o[8]=a00*s+a20*c;o[9]=a01*s+a21*c;o[10]=a02*s+a22*c;o[11]=a03*s+a23*c;
    return o;
  },
  invert(o,a){
    const a00=a[0],a01=a[1],a02=a[2],a03=a[3],a10=a[4],a11=a[5],a12=a[6],a13=a[7],
          a20=a[8],a21=a[9],a22=a[10],a23=a[11],a30=a[12],a31=a[13],a32=a[14],a33=a[15];
    const b00=a00*a11-a01*a10,b01=a00*a12-a02*a10,b02=a00*a13-a03*a10,
          b03=a01*a12-a02*a11,b04=a01*a13-a03*a11,b05=a02*a13-a03*a12,
          b06=a20*a31-a21*a30,b07=a20*a32-a22*a30,b08=a20*a33-a23*a30,
          b09=a21*a32-a22*a31,b10=a21*a33-a23*a31,b11=a22*a33-a23*a32;
    let d=b00*b11-b01*b10+b02*b09+b03*b08-b04*b07+b05*b06;
    if(!d)return null;d=1/d;
    o[0]=(a11*b11-a12*b10+a13*b09)*d;o[1]=(a02*b10-a01*b11-a03*b09)*d;
    o[2]=(a31*b05-a32*b04+a33*b03)*d;o[3]=(a22*b04-a21*b05-a23*b03)*d;
    o[4]=(a12*b08-a10*b11-a13*b07)*d;o[5]=(a00*b11-a02*b08+a03*b07)*d;
    o[6]=(a32*b02-a30*b05-a33*b01)*d;o[7]=(a20*b05-a22*b02+a23*b01)*d;
    o[8]=(a10*b10-a11*b08+a13*b06)*d;o[9]=(a01*b08-a00*b10-a03*b06)*d;
    o[10]=(a30*b04-a31*b02+a33*b00)*d;o[11]=(a21*b02-a20*b04-a23*b00)*d;
    o[12]=(a11*b07-a10*b09-a12*b06)*d;o[13]=(a00*b09-a01*b07+a02*b06)*d;
    o[14]=(a31*b01-a30*b03-a32*b00)*d;o[15]=(a20*b03-a21*b01+a22*b00)*d;
    return o;
  },
  transpose(o,a){
    o[0]=a[0];o[1]=a[4];o[2]=a[8];o[3]=a[12];
    o[4]=a[1];o[5]=a[5];o[6]=a[9];o[7]=a[13];
    o[8]=a[2];o[9]=a[6];o[10]=a[10];o[11]=a[14];
    o[12]=a[3];o[13]=a[7];o[14]=a[11];o[15]=a[15];
    return o;
  }
};

/* ===== SHADER SOURCES ===== */
const VERT=`
attribute vec3 aPos;
attribute vec3 aNorm;
attribute vec2 aUV;
uniform mat4 uMVP;
uniform mat4 uNormMat;
varying vec3 vNorm;
varying vec3 vPos;
varying vec2 vUV;
void main(){
  vec4 wp=uMVP*vec4(aPos,1.0);
  gl_Position=wp;
  vNorm=mat3(uNormMat)*aNorm;
  vPos=aPos;
  vUV=aUV;
}`;

const FRAG=`
precision mediump float;
varying vec3 vNorm;
varying vec3 vPos;
varying vec2 vUV;
uniform vec3 uLightDir;
uniform vec3 uCamPos;
uniform vec3 uBaseColor;
uniform vec3 uSpecColor;
uniform sampler2D uTex;
uniform float uTexOn;
uniform float uMetallic;
void main(){
  vec3 N=normalize(vNorm);
  vec3 L=normalize(uLightDir);
  vec3 V=normalize(uCamPos-vPos);
  vec3 H=normalize(L+V);
  float diff=max(dot(N,L),0.0);
  float spec=pow(max(dot(N,H),0.0),80.0);
  float fresnel=pow(1.0-max(dot(N,V),0.0),4.0);
  float amb=0.12;
  vec3 base=uBaseColor;
  vec3 texCol=vec3(1.0);
  if(uTexOn>0.5){
    texCol=texture2D(uTex,vUV).rgb;
  }
  vec3 col=base*(amb+diff*0.75);
  col+=spec*uSpecColor*1.2;
  col+=fresnel*base*0.35;
  col*=texCol;
  col=mix(col,base*0.08,0.0);
  gl_FragColor=vec4(col,1.0);
}`;

/* ===== WEBGL HELPERS ===== */
function compileShader(gl,src,type){
  const s=gl.createShader(type);
  gl.shaderSource(s,src);
  gl.compileShader(s);
  if(!gl.getShaderParameter(s,gl.COMPILE_STATUS)){
    console.error(gl.getShaderInfoLog(s));
    return null;
  }
  return s;
}
function createProgram(gl,vs,fs){
  const p=gl.createProgram();
  gl.attachShader(p,compileShader(gl,vs,gl.VERTEX_SHADER));
  gl.attachShader(p,compileShader(gl,fs,gl.FRAGMENT_SHADER));
  gl.linkProgram(p);
  if(!gl.getProgramParameter(p,gl.LINK_STATUS)){
    console.error(gl.getProgramInfoLog(p));
    return null;
  }
  return p;
}

/* ===== TEXTURE GENERATION ===== */
function makeFrontTexture(gl){
  const c=document.createElement('canvas');
  c.width=512;c.height=512;
  const x=c.getContext('2d');
  const cx=256,cy=256,r=240;
  // Background
  x.fillStyle='#1a1510';
  x.fillRect(0,0,512,512);
  // Coin base
  const g=x.createRadialGradient(cx-40,cy-40,10,cx,cy,r);
  g.addColorStop(0,'#c9a84c');
  g.addColorStop(0.5,'#a07830');
  g.addColorStop(1,'#6b5020');
  x.beginPath();x.arc(cx,cy,r,0,Math.PI*2);x.fillStyle=g;x.fill();
  // Outer ring
  x.beginPath();x.arc(cx,cy,r-8,0,Math.PI*2);x.strokeStyle='#8a6a20';x.lineWidth=4;x.stroke();
  x.beginPath();x.arc(cx,cy,r-14,0,Math.PI*2);x.strokeStyle='#d4b858';x.lineWidth=2;x.stroke();
  // Inner ring
  x.beginPath();x.arc(cx,cy,r-22,0,Math.PI*2);x.strokeStyle='#8a6a20';x.lineWidth=3;x.stroke();
  // Text around edge
  x.save();
  x.translate(cx,cy);
  x.font='bold 22px Georgia,serif';
  x.fillStyle='#5a4510';
  const text='WASTED TOKEN MINT';
  const chars=text.split('');
  const angleStep=(Math.PI*2)/chars.length;
  chars.forEach((ch,i)=>{
    const a=i*angleStep-Math.PI/2-Math.PI*0.02;
    x.save();
    x.rotate(a);
    x.fillText(ch,0,-r+42);
    x.restore();
  });
  x.restore();
  // Central emblem - stylized W
  x.save();
  x.translate(cx,cy);
  // Shield shape
  x.beginPath();
  x.moveTo(0,-80);
  x.lineTo(60,-50);
  x.lineTo(60,20);
  x.quadraticCurveTo(60,70,0,95);
  x.quadraticCurveTo(-60,70,-60,20);
  x.lineTo(-60,-50);
  x.closePath();
  const sg=x.createLinearGradient(-60,-80,60,95);
  sg.addColorStop(0,'#d4b858');
  sg.addColorStop(0.5,'#a07830');
  sg.addColorStop(1,'#6b5020');
  x.fillStyle=sg;
  x.fill();
  x.strokeStyle='#5a4510';
  x.lineWidth=3;
  x.stroke();
  // W letter
  x.font='bold 72px Georgia,serif';
  x.fillStyle='#3a2a08';
  x.textAlign='center';
  x.textBaseline='middle';
  x.fillText('W',0,5);
  // Highlight on W
  x.font='bold 72px Georgia,serif';
  x.fillStyle='rgba(212,184,88,0.3)';
  x.fillText('W',-2,-3);
  // Stars
  for(let i=0;i<8;i++){
    const a=i*Math.PI/4;
    const sx=Math.cos(a)*110;
    const sy=Math.sin(a)*110;
    x.beginPath();
    x.arc(sx,sy,4,0,Math.PI*2);
    x.fillStyle='#d4b858';
    x.fill();
  }
  x.restore();
  // Relief shadow effect
  const imgData=x.getImageData(0,0,512,512);
  const d=imgData.data;
  for(let y=1;y<511;y++){
    for(let px=1;px<511;px++){
      const i=(y*512+px)*4;
      const ri=(y*512+(px+1))*4;
      const bi=((y+1)*512+px)*4;
      const diffR=d[ri]-d[i];
      const diffB=d[bi]-d[i];
      const shade=(diffR+diffB)*0.08;
      d[i]=Math.max(0,Math.min(255,d[i]+shade));
      d[i+1]=Math.max(0,Math.min(255,d[i+1]+shade));
      d[i+2]=Math.max(0,Math.min(255,d[i+2]+shade));
    }
  }
  x.putImageData(imgData,0,0);
  const tex=gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D,tex);
  gl.texImage2D(gl.TEXTURE_2D,0,gl.RGBA,gl.RGBA,gl.UNSIGNED_BYTE,c);
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MIN_FILTER,gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MAG_FILTER,gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_S,gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_T,gl.CLAMP_TO_EDGE);
  return tex;
}

function makeBackTexture(gl){
  const c=document.createElement('canvas');
  c.width=512;c.height=512;
  const x=c.getContext('2d');
  const cx=256,cy=256,r=240;
  x.fillStyle='#1a1510';
  x.fillRect(0,0,512,512);
  const g=x.createRadialGradient(cx-40,cy-40,10,cx,cy,r);
  g.addColorStop(0,'#c9a84c');
  g.addColorStop(0.5,'#a07830');
  g.addColorStop(1,'#6b5020');
  x.beginPath();x.arc(cx,cy,r,0,Math.PI*2);x.fillStyle=g;x.fill();
  x.beginPath();x.arc(cx,cy,r-8,0,Math.PI*2);x.strokeStyle='#8a6a20';x.lineWidth=4;x.stroke();
  x.beginPath();x.arc(cx,cy,r-14,0,Math.PI*2);x.strokeStyle='#d4b858';x.lineWidth=2;x.stroke();
  x.beginPath();x.arc(cx,cy,r-22,0,Math.PI*2);x.strokeStyle='#8a6a20';x.lineWidth=3;x.stroke();
  // Denomination
  x.save();
  x.translate(cx,cy);
  x.font='bold 38px Georgia,serif';
  x.fillStyle='#3a2a08';
  x.textAlign='center';
  x.textBaseline='middle';
  x.fillText('10,000',0,-25);
  x.font='bold 28px Georgia,serif';
  x.fillText('TOKENS',0,20);
  // Highlight
  x.font='bold 38px Georgia,serif';
  x.fillStyle='rgba(212,184,88,0.25)';
  x.fillText('10,000',-2,-28);
  x.font='bold 28px Georgia,serif';
  x.fillText('TOKENS',-2,17);
  // Decorative lines
  x.strokeStyle='#5a4510';
  x.lineWidth=2;
  x.beginPath();x.moveTo(-80,-55);x.lineTo(80,-55);x.stroke();
  x.beginPath();x.moveTo(-70,45);x.lineTo(70,45);x.stroke();
  // Small stars
  for(let i=0;i<6;i++){
    const a=i*Math.PI/3-Math.PI/6;
    const sx=Math.cos(a)*130;
    const sy=Math.sin(a)*130;
    x.beginPath();
    // Star shape
    for(let j=0;j<5;j++){
      const sa=j*Math.PI*2/5-Math.PI/2;
      const sr=j%2===0?6:3;
      const px2=sx+Math.cos(sa)*sr;
      const py2=sy+Math.sin(sa)*sr;
      j===0?x.moveTo(px2,py2):x.lineTo(px2,py2);
    }
    x.closePath();
    x.fillStyle='#d4b858';
    x.fill();
  }
  // Year
  x.font='16px Georgia,serif';
  x.fillStyle='#5a4510';
  x.fillText('MMXXV',0,70);
  x.restore();
  // Relief
  const imgData=x.getImageData(0,0,512,512);
  const d=imgData.data;
  for(let y=1;y<511;y++){
    for(let px=1;px<511;px++){
      const i=(y*512+px)*4;
      const ri=(y*512+(px+1))*4;
      const bi=((y+1)*512+px)*4;
      const shade=((d[ri]-d[i])+(d[bi]-d[i]))*0.08;
      d[i]=Math.max(0,Math.min(255,d[i]+shade));
      d[i+1]=Math.max(0,Math.min(255,d[i+1]+shade));
      d[i+2]=Math.max(0,Math.min(255,d[i+2]+shade));
    }
  }
  x.putImageData(imgData,0,0);
  const tex=gl.createTexture();
  gl.bindTexture(gl.TEXTURE_2D,tex);
  gl.texImage2D(gl.TEXTURE_2D,0,gl.RGBA,gl.RGBA,gl.UNSIGNED_BYTE,c);
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MIN_FILTER,gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_MAG_FILTER,gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_S,gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D,gl.TEXTURE_WRAP_T,gl.CLAMP_TO_EDGE);
  return tex;
}

/* ===== GEOMETRY GENERATION ===== */
function createCoinGeometry(segments){
  const R=0.5, H=0.04, reeds=32;
  const verts=[];
  const idx=[];
  let vi=0;
  // Front face
  verts.push(0,0,H, 0,0,1, 0.5,0.5); // center
  for(let i=0;i<=segments;i++){
    const a=i/segments*Math.PI*2;
    const px=Math.cos(a)*R, py=Math.sin(a)*R;
    verts.push(px,py,H, 0,0,1, 0.5+Math.cos(a)*0.5,0.5+Math.sin(a)*0.5);
    if(i<segments){
      idx.push(vi,vi+1,vi+2);
      vi++;
    }
  }
  vi++; // skip center for next
  // Back face
  verts.push(0,0,-H, 0,0,-1, 0.5,0.5);
  for(let i=0;i<=segments;i++){
    const a=i/segments*Math.PI*2;
    const px=Math.cos(a)*R, py=Math.sin(a)*R;
    verts.push(px,py,-H, 0,0,-1, 0.5+Math.cos(a)*0.5,0.5+Math.sin(a)*0.5);
    if(i<segments){
      idx.push(vi,vi+2,vi+1);
      vi++;
    }
  }
  vi++;
  // Edge with reeds
  const edgeSegs=segments*2;
  for(let i=0;i<=edgeSegs;i++){
    const a=i/edgeSegs*Math.PI*2;
    const reedR=R+0.008*Math.sin(a*reedSegs/reeds);
    const px=Math.cos(a)*reedR, py=Math.sin(a)*reedR;
    const nx=Math.cos(a), ny=Math.sin(a);
    // Bottom
    verts.push(px,py,-H, nx,ny,0, i/edgeSegs,0);
    // Top
    verts.push(px,py,H, nx,ny,0, i/edgeSegs,1);
    if(i<edgeSegs){
      const b0=vi,b1=vi+1,b2=vi+2,b3=vi+3;
      idx.push(b0,b2,b1, b1,b2,b3);
      vi+=4;
    }
  }
  return{verts:new Float32Array(verts),idx:new Uint16Array(idx)};
}

/* ===== EDITION COLORS ===== */
const EDITION_COLORS={
  bronze:{base:[0.75,0.45,0.2],spec:[0.9,0.7,0.4]},
  silver:{base:[0.7,0.72,0.75],spec:[0.95,0.95,1.0]},
  gold:{base:[0.9,0.75,0.2],spec:[1.0,0.95,0.5]},
  black:{base:[0.12,0.12,0.15],spec:[0.4,0.4,0.5]}
};

/* ===== MAIN INIT ===== */
const heroCanvas=document.getElementById('coin-hero');
const gl=heroCanvas.getContext('webgl',{antialias:true,alpha:false});
if(!gl){document.body.innerHTML='<p style="color:red;text-align:center;padding:4rem">WebGL not supported.</p>';return;}

const prog=createProgram(gl,VERT,FRAG);
const aPos=gl.getAttribLocation(prog,'aPos');
const aNorm=gl.getAttribLocation(prog,'aNorm');
const aUV=gl.getAttribLocation(prog,'aUV');
const uMVP=gl.getUniformLocation(prog,'uMVP');
const uNormMat=gl.getUniformLocation(prog,'uNormMat');
const uLightDir=gl.getUniformLocation(prog,'uLightDir');
const uCamPos=gl.getUniformLocation(prog,'uCamPos');
const uBaseColor=gl.getUniformLocation(prog,'uBaseColor');
const uSpecColor=gl.getUniformLocation(prog,'uSpecColor');
const uTex=gl.getUniformLocation(prog,'uTex');
const uTexOn=gl.getUniformLocation(prog,'uTexOn');

const geo=createCoinGeometry(64);
const vbo=gl.createBuffer();
gl.bindBuffer(gl.ARRAY_BUFFER,vbo);
gl.bufferData(gl.ARRAY_BUFFER,geo.verts,gl.STATIC_DRAW);
const ibo=gl.createBuffer();
gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER,ibo);
gl.bufferData(gl.ELEMENT_ARRAY_BUFFER,geo.idx,gl.STATIC_DRAW);

const frontTex=makeFrontTexture(gl);
const backTex=makeBackTexture(gl);

gl.enable(gl.DEPTH_TEST);
gl.enable(gl.CULL_FACE);
gl.cullFace(gl.BACK);

const projMat=M4.create();
const viewMat=M4.create();
const modelMat=M4.create();
const mvpMat=M4.create();
const normMat=M4.create();
const mvMat=M4.create();

const lightDir=[0.4,0.6,0.8];
const camPos=[0,0,2.8];

let animTime=0;
let paused=false;
let rafId=null;

function renderCoin(t,baseColor,specColor,frontTexture,backTexture){
  const W=heroCanvas.width, H=heroCanvas.height;
  gl.viewport(0,0,W,H);
  gl.clearColor(0.03,0.03,0.06,1);
  gl.clear(gl.COLOR_BUFFER_BIT|gl.DEPTH_BUFFER_BIT);

  gl.useProgram(prog);

  // Projection
  M4.perspective(projMat,Math.PI/4,W/H,0.1,100);

  // View - camera at origin looking down -z, but we translate the coin back
  M4.identity(viewMat);

  // Model - rotation
  M4.identity(modelMat);
  const angleY=t*Math.PI*2;
  const angleX=Math.sin(t*Math.PI*2)*Math.PI;
  M4.rotateY(modelMat,modelMat,angleY);
  M4.rotateX(modelMat,modelMat,angleX);
  M4.translate(modelMat,modelMat,[0,0,-2.8]);

  // MVP
  M4.multiply(mvMat,viewMat,modelMat);
  M4.multiply(mvpMat,projMat,mvMat);

  // Normal matrix
  M4.invert(normMat,mvMat);
  M4.transpose(normMat,normMat);

  gl.uniformMatrix4fv(uMVP,false,mvpMat);
  gl.uniformMatrix4fv(uNormMat,false,normMat);
  gl.uniform3fv(uLightDir,lightDir);
  gl.uniform3fv(uCamPos,camPos);
  gl.uniform3fv(uBaseColor,baseColor);
  gl.uniform3fv(uSpecColor,specColor);

  // Bind attributes
  gl.bindBuffer(gl.ARRAY_BUFFER,vbo);
  gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER,ibo);
  const stride=8*4;
  gl.enableVertexAttribArray(aPos);
  gl.vertexAttribPointer(aPos,3,gl.FLOAT,false,stride,0);
  gl.enableVertexAttribArray(aNorm);
  gl.vertexAttribPointer(aNorm,3,gl.FLOAT,false,stride,3*4);
  gl.enableVertexAttribArray(aUV);
  gl.vertexAttribPointer(aUV,2,gl.FLOAT,false,stride,6*4);

  // Draw front face
  gl.activeTexture(gl.TEXTURE0);
  gl.bindTexture(gl.TEXTURE_2D,frontTexture);
  gl.uniform1i(uTex,0);
  gl.uniform1f(uTexOn,1.0);
  gl.drawElements(gl.TRIANGLES,64*3,gl.UNSIGNED_SHORT,0);

  // Draw back face
  gl.bindTexture(gl.TEXTURE_2D,backTexture);
  gl.drawElements(gl.TRIANGLES,64*3,gl.UNSIGNED_SHORT,64*3*2);

  // Draw edge (no texture)
  gl.uniform1f(uTexOn,0.0);
  const edgeIdxCount=(64*2)*2*6;
  gl.drawElements(gl.TRIANGLES,edgeIdxCount,gl.UNSIGNED_SHORT,(64*2+64*2)*2);
}

function render(t){
  renderCoin(t,[0.85,0.7,0.25],[1.0,0.95,0.6],frontTex,backTex);
}

function animate(){
  if(!paused){
    animTime+=0.004;
    if(animTime>1)animTime-=1;
  }
  render(animTime);
  rafId=requestAnimationFrame(animate);
}

/* ===== EDITION RENDERING (2D Canvas) ===== */
function renderEdition(canvas,edition){
  const ctx=canvas.getContext('2d');
  const w=canvas.width,h=canvas.height;
  const cx=w/2,cy=h/2,r=Math.min(w,h)*0.38;
  const colors=EDITION_COLORS[edition];
  const bc=colors.base,sc=colors.spec;

  // Background
  ctx.fillStyle='#0e0e18';
  ctx.fillRect(0,0,w,h);

  // Coin shadow
  ctx.save();
  ctx.beginPath();
  ctx.arc(cx+4,cy+6,r,0,Math.PI*2);
  ctx.fillStyle='rgba(0,0,0,0.5)';
  ctx.fill();
  ctx.restore();

  // Coin body
  const g=ctx.createRadialGradient(cx-r*0.3,cy-r*0.3,r*0.1,cx,cy,r);
  const r1=Math.round(bc[0]*255),g1=Math.round(bc[1]*255),b1=Math.round(bc[2]*255);
  const r2=Math.round(sc[0]*255),g2=Math.round(sc[1]*255),b2=Math.round(sc[2]*255);
  g.addColorStop(0,`rgb(${r2},${g2},${b2})`);
  g.addColorStop(0.4,`rgb(${r1},${g1},${b1})`);
  g.addColorStop(1,`rgb(${Math.round(r1*0.5)},${Math.round(g1*0.5)},${Math.round(b1*0.5)})`);
  ctx.beginPath();
  ctx.arc(cx,cy,r,0,Math.PI*2);
  ctx.fillStyle=g;
  ctx.fill();

  // Edge ring
  ctx.beginPath();
  ctx.arc(cx,cy,r-3,0,Math.PI*2);
  ctx.strokeStyle=`rgba(${Math.round(r1*0.6)},${Math.round(g1*0.6)},${Math.round(b1*0.6)},0.8)`;
  ctx.lineWidth=3;
  ctx.stroke();

  // Inner ring
  ctx.beginPath();
  ctx.arc(cx,cy,r-8,0,Math.PI*2);
  ctx.strokeStyle=`rgba(${Math.round(r2*0.7)},${Math.round(g2*0.7)},${Math.round(b2*0.7)},0.6)`;
  ctx.lineWidth=1.5;
  ctx.stroke();

  // Reeded edge effect
  for(let i=0;i<48;i++){
    const a=i/48*Math.PI*2;
    const x1=cx+Math.cos(a)*(r-2);
    const y1=cy+Math.sin(a)*(r-2);
    const x2=cx+Math.cos(a)*(r-5);
    const y2=cy+Math.sin(a)*(r-5);
    ctx.beginPath();
    ctx.moveTo(x1,y1);
    ctx.lineTo(x2,y2);
    ctx.strokeStyle=`rgba(${Math.round(r1*0.4)},${Math.round(g1*0.4)},${Math.round(b1*0.4)},0.5)`;
    ctx.lineWidth=1;
    ctx.stroke();
  }

  // Text
  ctx.save();
  ctx.translate(cx,cy);
  ctx.textAlign='center';
  ctx.textBaseline='middle';
  ctx.fillStyle=`rgb(${Math.round(r1*0.3)},${Math.round(g1*0.3)},${Math.round(b1*0.3)})`;
  ctx.font='bold 18px Georgia,serif';
  ctx.fillText('WASTED',0,-15);
  ctx.font='bold 14px Georgia,serif';
  ctx.fillText('TOKEN MINT',0,10);
  ctx.restore();

  // Specular highlight
  const sg=ctx.createRadialGradient(cx-r*0.4,cy-r*0.4,0,cx-r*0.4,cy-r*0.4,r*0.6);
  sg.addColorStop(0,'rgba(255,255,255,0.25)');
  sg.addColorStop(1,'rgba(255,255,255,0)');
  ctx.beginPath();
  ctx.arc(cx,cy,r,0,Math.PI*2);
  ctx.fillStyle=sg;
  ctx.fill();

  // Sold out overlay
  const ed=canvas.closest('.edition');
  if(ed&&ed.dataset.state==='sold-out'){
    ctx.save();
    ctx.translate(cx,cy);
    ctx.fillStyle='rgba(180,40,20,0.35)';
    ctx.fillRect(-r,-r,r*2,r*2);
    ctx.beginPath();ctx.arc(0,0,r,0,Math.PI*2);ctx.clip();
    ctx.fillStyle='rgba(180,40,20,0.3)';
    ctx.fillRect(-r,-r,r*2,r*2);
    ctx.font='bold 22px Georgia,serif';
    ctx.fillStyle='#c0392b';
    ctx.textAlign='center';
    ctx.textBaseline='middle';
    ctx.fillText('SOLD OUT',0,0);
    ctx.restore();
  }
  if(ed&&ed.dataset.state==='coming-soon'){
    ctx.save();
    ctx.translate(cx,cy);
    ctx.beginPath();ctx.arc(0,0,r,0,Math.PI*2);ctx.clip();
    ctx.fillStyle='rgba(20,40,80,0.25)';
    ctx.fillRect(-r,-r,r*2,r*2);
    ctx.font='bold 16px Georgia,serif';
    ctx.fillStyle='#3498db';
    ctx.textAlign='center';
    ctx.textBaseline='middle';
    ctx.fillText('COMING',0,-10);
    ctx.fillText('SOON',0,10);
    ctx.restore();
  }
}

/* ===== INIT EDITIONS ===== */
document.querySelectorAll('.edition').forEach(ed=>{
  const edition=ed.dataset.edition;
  const canvas=ed.querySelector('.edition-canvas');
  if(canvas&&edition)renderEdition(canvas,edition);
});

